/**
 * Type declarations for asset files
 */

// Database files
declare module '*.db' {
  const content: number;
  export default content;
}

// Database chunk files
declare module '*.1' {
  const content: number;
  export default content;
}

declare module '*.2' {
  const content: number;
  export default content;
}

declare module '*.3' {
  const content: number;
  export default content;
}
